import React from 'react';
import { Button, Card, Container, Row, Col } from "react-bootstrap";

function ViewCard({ card }) {

    return (
        <div>
            <Card>
                <Container>
                    <Row>
                        <Col>
                            <Card.Text>
                                {card.front}
                            </Card.Text>
                        </Col>
                        <Col>
                            <Card.Text>
                                {card.back}
                                <Button>Edit</Button>
                                <Button>Delete</Button>
                            </Card.Text>
                        </Col>
                    </Row>
                </Container>
            </Card>
        </div>
    )
}

export default ViewCard;
